  );

    const Login = () => {
        const [email, setEmail] = useState('');
        const [password, setPassword] = useState('');
        const [error, setError] = useState(''); // To handle error messages

        const handleEmailChange = (event) => {
            setEmail(event.target.value);
        };

        const handlePasswordChange = (event) => {
            setPassword(event.target.value);
        };

        const handleLoginSubmit = async (e) => {
            e.preventDefault();
            try {
                const response = await AuthService.login(email, password);

                if (response && response.userId) {
                    userRepository.setCurrentUser(response);
                    console.log("Logged in user:", response);

                    const roleResponse = await AuthService.getUserRole(response.userId);
                    if (roleResponse && roleResponse.role) {
                        userRepository.setCurrentAccountType(roleResponse.role);
                        console.log("User role set to:", roleResponse.role);
                    } else {
                        console.warn("User role not found.");
                    }

                    const tokenResponse = await AuthService.getToken(email, password);
                    if (tokenResponse && tokenResponse.token) {
                        userRepository.setJwtToken(tokenResponse.token);
                        console.log("JWT token set.");
                    }

                    navigateTo("userMain");
                } else {
                    setError('Invalid credentials or user not found');
                }
            } catch (error) {
                console.error("Error during login:", error);
                setError('Login failed. Please try again.');
            }
        };

        return (
            <div
                className="login-container"
                style={{
                    backgroundImage: `url(${loginBackgroundImg})`,
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                }}
            >
                <div className="login-form-container">
                    <h1>Login</h1>
                    <form onSubmit={handleLoginSubmit}>
                        <input
                            type="email"
                            placeholder="Email"
                            value={email}
                            onChange={handleEmailChange}
                            required
                        />
                        <input
                            type="password"
                            placeholder="Password"
                            value={password}
                            onChange={handlePasswordChange}
                            required
                        />
                        <button type="submit">Login</button>
                    </form>
                    {error && <p className="error-message">{error}</p>}

                    <button onClick={() => navigateTo('home')} className="back-button">
                        Back to Home
                    </button>

                    <p className="create-account-option">
                        Don't have an account yet?{" "}
                        <span
                            className="create-account-link"
                            onClick={() => navigateTo('createAccount')}
                        >
                        Create one
                    </span>
                    </p>

                    <p className="forgot-password-option">
                        Forgot your password?{" "}
                        <span
                            className="forgot-password-link"
                            onClick={() => navigateTo('forgotPassword')}
                        >
                        Reset it here
                    </span>
                    </p>
                </div>
            </div>
        );
    };

    const ForgotPassword = () => {
        const [email, setEmail] = useState("");
        const [message, setMessage] = useState("");
        const [error, setError] = useState("");

        const handleEmailChange = (event) => {
            setEmail(event.target.value);
        };

        const handleForgotPasswordSubmit = async (e) => {
            e.preventDefault();
            try {
                const response = await AuthService.forgotPassword(email);
                if (response && response.message) {
                    setMessage("Check your email for password reset instructions.");
                    setError("");
                } else {
                    setError("Email not found.");
                    setMessage("");
                }
            } catch (error) {
                console.error("Password reset failed:", error);
                setError("Something went wrong. Please try again.");
                setMessage("");
            }
        };

        return (
            <div
                className="forgot-password-container"
                style={{
                    backgroundImage: `url(${passwordImg})`,
                    backgroundSize: "cover",
                    backgroundPosition: "center",
                }}
            >
                <div className="forgot-password-form-container">
                    <h1>Forgot Password</h1>
                    <form onSubmit={handleForgotPasswordSubmit}>
                        <input
                            type="email"
                            placeholder="Enter your email"
                            value={email}
                            onChange={handleEmailChange}
                            required
                        />
                        <button type="submit">Send Reset Link</button>
                    </form>

                    {message && <p className="success-message">{message}</p>}
                    {error && <p className="error-message">{error}</p>}

                    <button onClick={() => navigateTo("login")} className="back-button">
                        Back to Login
                    </button>
                </div>
            </div>
        );
    };

    const ResetPassword = () => {
        const location = useLocation();
        const params = new URLSearchParams(location.search);
        const token = params.get("token");

        const [newPassword, setNewPassword] = useState("");
        const [confirmPassword, setConfirmPassword] = useState("");
        const [message, setMessage] = useState("");
        const [error, setError] = useState("");

        const handleSubmit = async (e) => {
            e.preventDefault();

            if (newPassword !== confirmPassword) {
                setError("Passwords do not match.");
                setMessage("");
                return;
            }

            try {
                const data = await AuthService.resetPassword(token, newPassword); // Already JSON

                if (data && data.success) {
                    setMessage("Your password has been reset successfully.");
                    setError("");

                    setTimeout(() => {
                        navigateTo("login");
                    }, 2000);
                } else {
                    setError(data?.message || "Invalid or expired reset link.");
                    setMessage("");
                }
            } catch (err) {
                console.error("Password reset failed:", err);
                setError("Something went wrong. Please try again.");
                setMessage("");
            }
        };

        return (
            <div
                className="forgot-password-container"
                style={{
                    backgroundImage: `url(${passwordImg})`,
                    backgroundSize: "cover",
                    backgroundPosition: "center",
                }}
            >
                <div className="forgot-password-form-container">
                    <h1>Reset Password</h1>
                    <form onSubmit={handleSubmit}>
                        <input
                            type="password"
                            placeholder="New password"
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                            required
                        />
                        <input
                            type="password"
                            placeholder="Confirm new password"
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                            required
                        />
                        <button type="submit">Reset Password</button>
                    </form>

                    {message && <p className="success-message">{message}</p>}
                    {error && <p className="error-message">{error}</p>}
                </div>
            </div>
        );
    };


    const CreateAccount = () => {
        const [fullName, setFullName] = useState("");
        const [email, setEmail] = useState("");
        const [password, setPassword] = useState("");

        const handleFullNameChange = (event) => setFullName(event.target.value);
        const handleEmailChange = (event) => setEmail(event.target.value);
        const handlePasswordChange = (event) => setPassword(event.target.value);

        const handleSubmit = (event) => {
            event.preventDefault();

            fetch("http://localhost:8080/create-account", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({ fullName, email, password }),
            })
                .then((response) => {
                    if (!response.ok) {
                        throw new Error("Failed to create account");
                    }
                    return response.json();
                })
                .then((data) => {
                    // Assuming the response contains the full user data including userId
                    const { userId, fullName, email } = data; // This may change based on your API response
                    userRepository.setCurrentUser({ userId, fullName, email, password });

                    console.log("User created successfully:", data);

                    navigateTo("accountType");
                })
                .catch((error) => {
                    handleApiError(error);
                });
