                            type="email"
                            placeholder="Email"
                            value={email}
                            onChange={handleEmailChange}
                            required
                        />
                        <input
                            type="password"
                            placeholder="Password"
                            value={password}
                            onChange={handlePasswordChange}
                            required
                        />
                        <button type="submit">Sign Up</button>
                    </form>
                    <button onClick={() => navigateTo("login")} className="back-button">
